package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.TreeTypeAdapter;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

import java.lang.reflect.Type;
import java.util.List;
import java.util.Map;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void registerTypeAdapter_withNullType_throwsNullPointerException() {
    assertThrows(NullPointerException.class, () -> gsonBuilder.registerTypeAdapter(null, new Object()));
  }

  @Test
  void registerTypeAdapter_withInvalidTypeAdapter_throwsIllegalArgumentException() {
    Object invalidAdapter = new Object();
    Type type = String.class;
    assertThrows(IllegalArgumentException.class, () -> gsonBuilder.registerTypeAdapter(type, invalidAdapter));
  }

  @Test
  void registerTypeAdapter_withInstanceCreator_addsToInstanceCreators() {
    Type type = String.class;
    InstanceCreator<String> instanceCreator = mock(InstanceCreator.class);

    GsonBuilder returned = gsonBuilder.registerTypeAdapter(type, instanceCreator);

    assertSame(gsonBuilder, returned);
    Map<Type, InstanceCreator<?>> instanceCreators = getInstanceCreators(gsonBuilder);
    assertEquals(instanceCreator, instanceCreators.get(type));
  }

  @Test
  void registerTypeAdapter_withJsonSerializer_addsFactory() {
    Type type = String.class;
    JsonSerializer<String> serializer = mock(JsonSerializer.class);

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterMockedStatic = mockStatic(TreeTypeAdapter.class)) {
      TypeToken<String> typeToken = TypeToken.get(type);
      TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);
      treeTypeAdapterMockedStatic.when(() -> TreeTypeAdapter.newFactoryWithMatchRawType(typeToken, serializer))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeAdapter(type, serializer);

      assertSame(gsonBuilder, returned);
      List<TypeAdapterFactory> factories = getFactories(gsonBuilder);
      assertTrue(factories.contains(factoryMock));
      treeTypeAdapterMockedStatic.verify(() -> TreeTypeAdapter.newFactoryWithMatchRawType(typeToken, serializer));
    }
  }

  @Test
  void registerTypeAdapter_withJsonDeserializer_addsFactory() {
    Type type = String.class;
    JsonDeserializer<String> deserializer = mock(JsonDeserializer.class);

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterMockedStatic = mockStatic(TreeTypeAdapter.class)) {
      TypeToken<String> typeToken = TypeToken.get(type);
      TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);
      treeTypeAdapterMockedStatic.when(() -> TreeTypeAdapter.newFactoryWithMatchRawType(typeToken, deserializer))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeAdapter(type, deserializer);

      assertSame(gsonBuilder, returned);
      List<TypeAdapterFactory> factories = getFactories(gsonBuilder);
      assertTrue(factories.contains(factoryMock));
      treeTypeAdapterMockedStatic.verify(() -> TreeTypeAdapter.newFactoryWithMatchRawType(typeToken, deserializer));
    }
  }

  @Test
  void registerTypeAdapter_withTypeAdapter_addsFactory() {
    Type type = String.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<String> typeAdapter = mock(TypeAdapter.class);

    try (MockedStatic<TypeAdapters> typeAdaptersMockedStatic = mockStatic(TypeAdapters.class)) {
      TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);
      typeAdaptersMockedStatic.when(() -> TypeAdapters.newFactory(TypeToken.get(type), typeAdapter))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeAdapter(type, typeAdapter);

      assertSame(gsonBuilder, returned);
      List<TypeAdapterFactory> factories = getFactories(gsonBuilder);
      assertTrue(factories.contains(factoryMock));
      typeAdaptersMockedStatic.verify(() -> TypeAdapters.newFactory(TypeToken.get(type), typeAdapter));
    }
  }

  @Test
  void registerTypeAdapter_withMultipleInterfaces_addsAllRelevant() {
    Type type = String.class;
    Object multiAdapter = new JsonSerializer<String>() implements JsonDeserializer<String>, InstanceCreator<String>, TypeAdapter<String> {
      @Override
      public JsonElement serialize(String src, Type typeOfSrc, JsonSerializationContext context) {
        return null;
      }
      @Override
      public String deserialize(JsonElement json, Type typeOfT, JsonDeserializationContext context) {
        return null;
      }
      @Override
      public String createInstance(Type type) {
        return null;
      }
      @Override
      public String read(JsonReader in) {
        return null;
      }
      @Override
      public void write(JsonWriter out, String value) {
      }
    };

    // Because of the anonymous class, we cannot mock static calls easily for TreeTypeAdapter and TypeAdapters.
    // Instead, test the instanceCreators map is updated and factories size increases.
    int initialFactoriesSize = getFactories(gsonBuilder).size();

    // Use a spy to verify the factories list additions indirectly
    GsonBuilder spyBuilder = spy(gsonBuilder);

    doCallRealMethod().when(spyBuilder).registerTypeAdapter(eq(type), eq(multiAdapter));

    GsonBuilder returned = spyBuilder.registerTypeAdapter(type, multiAdapter);

    assertSame(spyBuilder, returned);
    Map<Type, InstanceCreator<?>> instanceCreators = getInstanceCreators(spyBuilder);
    assertTrue(instanceCreators.containsKey(type));
    List<TypeAdapterFactory> factories = getFactories(spyBuilder);
    assertTrue(factories.size() >= initialFactoriesSize);
  }

  // Helper methods to access private fields via reflection
  @SuppressWarnings("unchecked")
  private Map<Type, InstanceCreator<?>> getInstanceCreators(GsonBuilder builder) {
    try {
      var field = GsonBuilder.class.getDeclaredField("instanceCreators");
      field.setAccessible(true);
      return (Map<Type, InstanceCreator<?>>) field.get(builder);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }

  @SuppressWarnings("unchecked")
  private List<TypeAdapterFactory> getFactories(GsonBuilder builder) {
    try {
      var field = GsonBuilder.class.getDeclaredField("factories");
      field.setAccessible(true);
      return (List<TypeAdapterFactory>) field.get(builder);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }
}
